/**
 * E2E Test: Extended API Coverage
 * Testa endpoints adicionais da API: render, import, storage, monitoring, subscription.
 * Foco em validação de contratos, proteção e error handling.
 */

import { test, expect } from '@playwright/test';

// -------------------------------------------------------
// Render API endpoints
// -------------------------------------------------------
test.describe('API Render', () => {
  test('GET /api/render/start responds with expected structure', async ({ request }) => {
    const response = await request.get('/api/render/start?action=video-test');
    const status = response.status();
    expect(status).toBeLessThan(500);
    if (status === 200) {
      const body = await response.json();
      expect(body).toBeDefined();
    }
  });

  test('POST /api/render/start without body fails gracefully', async ({ request }) => {
    const response = await request.post('/api/render/start', {
      data: {},
      headers: { 'Content-Type': 'application/json' },
    });
    expect(response.status()).toBeLessThan(500);
  });

  test('GET /api/render-status without id returns error', async ({ request }) => {
    const response = await request.get('/api/render-status');
    const status = response.status();
    // Should return 400 or 404 for missing id, not 500
    expect(status).toBeLessThan(500);
  });
});

