// -------------------------------------------------------
// Error handling — malformed requests
// -------------------------------------------------------
test.describe('API Error Handling', () => {
  test('POST with malformed JSON returns 400', async ({ request }) => {
    const response = await request.post('/api/tts/synthesize', {
      data: 'this is not JSON',
      headers: { 'Content-Type': 'application/json' },
    });
    const status = response.status();
    // Should handle gracefully — 400 is ideal but any non-500 is acceptable
    expect(status).toBeLessThan(500);
  });

  test('Non-existent API route returns 404', async ({ request }) => {
    const response = await request.get('/api/this-route-does-not-exist-xyz');
    const status = response.status();
    expect(status).toBe(404);
  });

  test('API responds with JSON content-type on errors', async ({ request }) => {
    const response = await request.get('/api/this-route-does-not-exist-xyz');
    const contentType = response.headers()['content-type'] || '';
    // Error responses should indicate they are not HTML pages
    // Accept JSON or text responses
    expect(
      contentType.includes('json') ||
      contentType.includes('text') ||
      response.status() === 404
    ).toBeTruthy();
  });
});
